-- -- @(#) $GenPackageDir$/$GenFileName$ $MssDoubleDashScriptLicense$ delimiter //// create function $lower DbSchemaName$.$sp_next_schemaidgen$() returns smallint modifies sql data not deterministic begin declare SliceId smallint default $Slice$; declare NextId smallint;
if not exists ( select * from $lower DbSchemaName$.$DbSchemaName$_idg16 where slice_id = SliceId ) then insert into $lower DbSchemaName$.$DbSchemaName$_idg16 ( slice_id, next_id ) values ( SliceId, 1 ); end if;
select next_id into NextId from $lower DbSchemaName$.$DbSchemaName$_idg16 where slice_id = SliceId for update;
update $lower DbSchemaName$.$DbSchemaName$_idg16 set next_id = NextId + 1 where slice_id = SliceId;
return NextId; end;////

